/*
 * COMP 421 Lab 2: Yalnix Operating System Kernel
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>

#include <comp421/hardware.h>
#include <comp421/loadinfo.h>
#include <comp421/yalnix.h>

/* ========================================================================
 * Constants
 * ======================================================================== */

#define MAX_PROCESSES    128
#define CLOCK_QUANTUM    2

/* ========================================================================
 * Data Structures
 * ======================================================================== */

/* Process states */
typedef enum {
    PROC_FREE = 0,
    PROC_RUNNING,
    PROC_READY,
    PROC_BLOCKED_DELAY,
    PROC_BLOCKED_WAIT,
    PROC_BLOCKED_TTY_READ,
    PROC_BLOCKED_TTY_WRITE,
    PROC_ZOMBIE
} proc_state_t;

/* Process Control Block */
typedef struct pcb {
    int pid;
    proc_state_t state;
    SavedContext ctx;
    struct pte *pt0;            /* Region 0 page table (virtual addr) */
    unsigned long pt0_phys;     /* Region 0 page table physical addr */
    void *brk;                  /* User break address */
    void *user_stack_base;      /* Base of allocated user stack */
    int clock_ticks;            /* Ticks since last scheduled */
    int delay_ticks;            /* Remaining delay ticks */
    int exit_status;            /* Exit status for zombie */
    struct pcb *parent;
    struct pcb *next;           /* For linked lists (ready queue, etc.) */

    /* Children tracking */
    struct pcb *children;       /* Head of children list */
    struct pcb *sibling;        /* Next sibling in parent's children list */

    /* Zombie children queue for Wait */
    struct pcb *zombie_head;
    struct pcb *zombie_tail;
    struct pcb *zombie_next;    /* Next in zombie queue */

    ExceptionInfo *user_info;   /* Pointer to the exception info on kernel stack */
} pcb_t;

/* TTY input buffer node */
typedef struct tty_buf {
    char data[TERMINAL_MAX_LINE];
    int len;
    int offset;                 /* How much has been read so far */
    struct tty_buf *next;
} tty_buf_t;

/* ========================================================================
 * Global Variables
 * ======================================================================== */

static int vm_enabled = 0;
static void *kernel_brk;               /* Current kernel break */
static void *kernel_brk_init;          /* Break at boot before VM */

/* Page tables */
static struct pte *kernel_pt1;          /* Region 1 page table (virt addr) */
static unsigned long kernel_pt1_phys;   /* Region 1 page table phys addr */

/* Free physical frame list */
static int *free_frames;        /* Array of free frame numbers */
static int free_frame_count;
static int total_frames;

/* Process table */
static pcb_t *proc_table[MAX_PROCESSES];
static pcb_t *current_proc;
static pcb_t *idle_proc;
static int next_pid = 0;

/* Ready queue */
static pcb_t *ready_head;
static pcb_t *ready_tail;

/* Delay queue */
static pcb_t *delay_head;

/* Interrupt vector table */
static void (*interrupt_vector[TRAP_VECTOR_SIZE])(ExceptionInfo *);

/* TTY state */
static tty_buf_t *tty_read_bufs[NUM_TERMINALS];     /* Input buffer queues */
static pcb_t *tty_read_blocked[NUM_TERMINALS];       /* Processes blocked on TtyRead */
static pcb_t *tty_write_active[NUM_TERMINALS];       /* Currently writing process */
static pcb_t *tty_write_queue[NUM_TERMINALS];        /* Queue of waiting writers */

/* Transmit buffers - we need kernel-space copies for TtyTransmit */
static char tty_xmit_buf[NUM_TERMINALS][TERMINAL_MAX_LINE];

/* ========================================================================
 * Forward Declarations
 * ======================================================================== */

static int alloc_frame(void);
static void free_frame(int pfn);
static void enqueue_ready(pcb_t *p);
static pcb_t *dequeue_ready(void);
static void schedule(ExceptionInfo *info);
static void switch_to(pcb_t *next, ExceptionInfo *info);
static SavedContext *MySwitchFunc(SavedContext *ctxp, void *p1, void *p2);
static SavedContext *ForkSwitchFunc(SavedContext *ctxp, void *p1, void *p2);
static SavedContext *InitIdleSwitchFunc(SavedContext *ctxp, void *p1, void *p2);
static pcb_t *create_pcb(void);
static void destroy_process(pcb_t *p);
static int LoadProgram(char *name, char **args, pcb_t *proc, ExceptionInfo *info);
static int validate_user_buf(pcb_t *proc, void *buf, int len, int need_write);
static int validate_user_string(pcb_t *proc, char *str);

/* Trap handlers */
static void trap_kernel(ExceptionInfo *info);
static void trap_clock(ExceptionInfo *info);
static void trap_illegal(ExceptionInfo *info);
static void trap_memory(ExceptionInfo *info);
static void trap_math(ExceptionInfo *info);
static void trap_tty_receive(ExceptionInfo *info);
static void trap_tty_transmit(ExceptionInfo *info);

/* Kernel call implementations */
static int kern_fork(ExceptionInfo *info);
static int kern_exec(char *filename, char **argvec, ExceptionInfo *info);
static void kern_exit(int status, ExceptionInfo *info);
static int kern_wait(int *status_ptr, ExceptionInfo *info);
static int kern_getpid(void);
static int kern_brk(void *addr);
static int kern_delay(int ticks, ExceptionInfo *info);
static int kern_ttyread(int tty_id, void *buf, int len, ExceptionInfo *info);
static int kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info);

/* ========================================================================
 * Physical Frame Management
 * ======================================================================== */

static int
alloc_frame(void)
{
    if (free_frame_count <= 0) return -1;
    free_frame_count--;
    return free_frames[free_frame_count];
}

static void
free_frame(int pfn)
{
    free_frames[free_frame_count] = pfn;
    free_frame_count++;
}

/* ========================================================================
 * Queue Management
 * ======================================================================== */

static void
enqueue_ready(pcb_t *p)
{
    p->state = PROC_READY;
    p->next = NULL;
    if (ready_tail) {
        ready_tail->next = p;
    } else {
        ready_head = p;
    }
    ready_tail = p;
}

static pcb_t *
dequeue_ready(void)
{
    pcb_t *p = ready_head;
    if (p) {
        ready_head = p->next;
        if (!ready_head) ready_tail = NULL;
        p->next = NULL;
    }
    return p;
}

/* ========================================================================
 * Context Switching
 * ======================================================================== */

static SavedContext *
MySwitchFunc(SavedContext *ctxp, void *p1, void *p2)
{
    pcb_t *old = (pcb_t *)p1;
    pcb_t *new = (pcb_t *)p2;

    /* Save context in old PCB */
    old->ctx = *ctxp;

    /* Switch Region 0 page table */
    WriteRegister(REG_PTR0, new->pt0_phys);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    return &new->ctx;
}

static SavedContext *
ForkSwitchFunc(SavedContext *ctxp, void *p1, void *p2)
{
    pcb_t *parent = (pcb_t *)p1;
    pcb_t *child = (pcb_t *)p2;
    int i;

    /* Save context in both parent and child */
    parent->ctx = *ctxp;
    child->ctx = *ctxp;

    /* Copy kernel stack pages from parent to child.
     * We use a temporary mapping in Region 1 to write to child's physical pages.
     * We'll use the page just above the current kernel break for temp mapping.
     */
    int temp_vpn = (VMEM_1_BASE >> PAGESHIFT) + PAGE_TABLE_LEN - 1; /* Use last Region 1 page */
    int temp_idx = PAGE_TABLE_LEN - 1;

    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int src_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + i;
        int child_pfn = child->pt0[src_vpn].pfn;

        /* Temporarily map child's physical page into Region 1 */
        struct pte old_pte = kernel_pt1[temp_idx];
        kernel_pt1[temp_idx].valid = 1;
        kernel_pt1[temp_idx].kprot = PROT_READ | PROT_WRITE;
        kernel_pt1[temp_idx].uprot = PROT_NONE;
        kernel_pt1[temp_idx].pfn = child_pfn;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));

        /* Copy from parent's kernel stack to temp-mapped child page */
        memcpy((void *)(temp_vpn << PAGESHIFT),
               (void *)((src_vpn) << PAGESHIFT),
               PAGESIZE);

        /* Restore old mapping */
        kernel_pt1[temp_idx] = old_pte;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));
    }

    /* Stay on parent's Region 0 — don't switch */
    return &parent->ctx;
}

static SavedContext *
InitIdleSwitchFunc(SavedContext *ctxp, void *p1, void *p2)
{
    pcb_t *proc = (pcb_t *)p1;
    (void)p2;

    /* Save context */
    proc->ctx = *ctxp;

    return ctxp;
}

/* ========================================================================
 * Process Scheduling
 * ======================================================================== */

static void
switch_to(pcb_t *next, ExceptionInfo *info)
{
    pcb_t *old;
    (void)info;

    if (next == current_proc) return;

    old = current_proc;
    current_proc = next;
    next->state = PROC_RUNNING;
    next->clock_ticks = 0;

    ContextSwitch(MySwitchFunc, &old->ctx, (void *)old, (void *)next);
}

static void
schedule(ExceptionInfo *info)
{
    pcb_t *next = dequeue_ready();
    if (!next) {
        /* No ready processes, run idle */
        if (current_proc == idle_proc) return;
        next = idle_proc;
    }
    switch_to(next, info);
}

/* ========================================================================
 * Validation Helpers
 * ======================================================================== */

static int
validate_user_buf(pcb_t *proc, void *buf, int len, int need_write)
{
    unsigned long start = (unsigned long)buf;
    unsigned long end = start + len;
    unsigned long page_start, vpn;

    if (len == 0) return 0;
    if (start >= VMEM_0_LIMIT || end > VMEM_0_LIMIT) return -1;
    if (start >= KERNEL_STACK_BASE) return -1;  /* Can't access kernel stack */

    for (page_start = DOWN_TO_PAGE(start); page_start < end; page_start += PAGESIZE) {
        vpn = page_start >> PAGESHIFT;
        if (vpn >= PAGE_TABLE_LEN) return -1;
        if (!proc->pt0[vpn].valid) return -1;
        if (need_write && !(proc->pt0[vpn].uprot & PROT_WRITE)) return -1;
        if (!need_write && !(proc->pt0[vpn].uprot & PROT_READ)) return -1;
    }
    return 0;
}

static int
validate_user_string(pcb_t *proc, char *str)
{
    unsigned long addr = (unsigned long)str;
    unsigned long vpn;

    if (addr >= VMEM_0_LIMIT || addr >= KERNEL_STACK_BASE) return -1;

    while (1) {
        vpn = addr >> PAGESHIFT;
        if (vpn >= PAGE_TABLE_LEN) return -1;
        if (!proc->pt0[vpn].valid) return -1;
        if (!(proc->pt0[vpn].uprot & PROT_READ)) return -1;
        if (*(char *)addr == '\0') return 0;
        addr++;
        if (addr >= VMEM_0_LIMIT || addr >= KERNEL_STACK_BASE) return -1;
    }
}

/* ========================================================================
 * Process Creation/Destruction
 * ======================================================================== */

static pcb_t *
create_pcb(void)
{
    pcb_t *p;
    int i, pfn;

    if (next_pid >= MAX_PROCESSES) return NULL;

    p = (pcb_t *)malloc(sizeof(pcb_t));
    if (!p) return NULL;
    memset(p, 0, sizeof(pcb_t));

    p->pid = next_pid++;
    p->state = PROC_FREE;

    /* Allocate Region 0 page table - needs to be page-aligned and contiguous.
     * PAGE_TABLE_SIZE is the size of a page table.
     * We allocate a frame for the page table itself.
     */
    p->pt0 = (struct pte *)malloc(PAGE_TABLE_SIZE);
    if (!p->pt0) {
        free(p);
        return NULL;
    }
    memset(p->pt0, 0, PAGE_TABLE_SIZE);

    /* We need the physical address of pt0. Since it's in Region 1 (kernel heap),
     * we can look up its physical address through the Region 1 page table. */
    {
        unsigned long vaddr = (unsigned long)p->pt0;
        unsigned long vpn1 = (vaddr - VMEM_1_BASE) >> PAGESHIFT;
        unsigned long offset = vaddr & PAGEOFFSET;
        p->pt0_phys = (kernel_pt1[vpn1].pfn << PAGESHIFT) + offset;
    }

    /* Allocate kernel stack pages */
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        pfn = alloc_frame();
        if (pfn < 0) {
            /* Free already allocated pages */
            int j;
            for (j = 0; j < i; j++) {
                int kstack_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
                free_frame(p->pt0[kstack_vpn].pfn);
            }
            free(p->pt0);
            free(p);
            return NULL;
        }
        int kstack_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + i;
        p->pt0[kstack_vpn].valid = 1;
        p->pt0[kstack_vpn].kprot = PROT_READ | PROT_WRITE;
        p->pt0[kstack_vpn].uprot = PROT_NONE;
        p->pt0[kstack_vpn].pfn = pfn;
    }

    proc_table[p->pid] = p;
    return p;
}

static void
destroy_process(pcb_t *p)
{
    int i;

    /* Free all valid Region 0 pages */
    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        if (p->pt0[i].valid) {
            free_frame(p->pt0[i].pfn);
            p->pt0[i].valid = 0;
        }
    }

    /* Remove from parent's children list */
    if (p->parent) {
        pcb_t **pp = &p->parent->children;
        while (*pp) {
            if (*pp == p) {
                *pp = p->sibling;
                break;
            }
            pp = &(*pp)->sibling;
        }
    }

    /* Orphan all children */
    {
        pcb_t *child = p->children;
        while (child) {
            pcb_t *next_child = child->sibling;
            child->parent = NULL;
            child->sibling = NULL;
            /* If child is zombie with no parent, free it */
            if (child->state == PROC_ZOMBIE) {
                proc_table[child->pid] = NULL;
                free(child->pt0);
                free(child);
            }
            child = next_child;
        }
    }

    /* Free zombie children */
    {
        pcb_t *z = p->zombie_head;
        while (z) {
            pcb_t *next_z = z->zombie_next;
            proc_table[z->pid] = NULL;
            free(z->pt0);
            free(z);
            z = next_z;
        }
    }

    proc_table[p->pid] = NULL;
    free(p->pt0);
    free(p);
}

/* ========================================================================
 * Trap Handlers
 * ======================================================================== */

static void
trap_kernel(ExceptionInfo *info)
{
    int call_num = info->code;
    int rc;

    switch (call_num) {
    case YALNIX_FORK:
        rc = kern_fork(info);
        info->regs[0] = rc;
        break;
    case YALNIX_EXEC:
        rc = kern_exec((char *)info->regs[1], (char **)info->regs[2], info);
        info->regs[0] = rc;
        break;
    case YALNIX_EXIT:
        kern_exit((int)info->regs[1], info);
        /* Does not return for this process */
        break;
    case YALNIX_WAIT:
        rc = kern_wait((int *)info->regs[1], info);
        info->regs[0] = rc;
        break;
    case YALNIX_GETPID:
        info->regs[0] = kern_getpid();
        break;
    case YALNIX_BRK:
        rc = kern_brk((void *)info->regs[1]);
        info->regs[0] = rc;
        break;
    case YALNIX_DELAY:
        rc = kern_delay((int)info->regs[1], info);
        info->regs[0] = rc;
        break;
    case YALNIX_TTY_READ:
        rc = kern_ttyread((int)info->regs[1], (void *)info->regs[2],
                          (int)info->regs[3], info);
        info->regs[0] = rc;
        break;
    case YALNIX_TTY_WRITE:
        rc = kern_ttywrite((int)info->regs[1], (void *)info->regs[2],
                           (int)info->regs[3], info);
        info->regs[0] = rc;
        break;
    default:
        TracePrintf(0, "Unknown kernel call %d from pid %d\n",
                    call_num, current_proc->pid);
        info->regs[0] = ERROR;
        break;
    }
}

static void
trap_clock(ExceptionInfo *info)
{
    /* Decrement delay counters */
    pcb_t *prev = NULL;
    pcb_t *p = delay_head;

    while (p) {
        p->delay_ticks--;
        pcb_t *next = p->next;
        if (p->delay_ticks <= 0) {
            /* Remove from delay list */
            if (prev) prev->next = next;
            else delay_head = next;
            enqueue_ready(p);
        } else {
            prev = p;
        }
        p = next;
    }

    /* Round-robin scheduling */
    if (current_proc != idle_proc) {
        current_proc->clock_ticks++;
        if (current_proc->clock_ticks >= CLOCK_QUANTUM && ready_head != NULL) {
            enqueue_ready(current_proc);
            schedule(info);
        }
    } else {
        /* Idle process running, switch if something is ready */
        if (ready_head != NULL) {
            schedule(info);
        }
    }
}

static void
trap_illegal(ExceptionInfo *info)
{
    TracePrintf(0, "TRAP_ILLEGAL: Process %d terminated (illegal instruction at %p)\n",
                current_proc->pid, info->pc);
    fprintf(stderr, "Process %d terminated: illegal instruction\n", current_proc->pid);
    kern_exit(ERROR, info);
}

static void
trap_memory(ExceptionInfo *info)
{
    unsigned long addr = (unsigned long)info->addr;

    /* Check if this is a stack growth request */
    if (addr < VMEM_0_LIMIT && addr >= MEM_INVALID_SIZE) {
        unsigned long brk_page = (unsigned long)UP_TO_PAGE(current_proc->brk);
        unsigned long stack_base;
        unsigned long page_addr;
        int vpn;

        /* Find current bottom of user stack */
        stack_base = (unsigned long)USER_STACK_LIMIT;
        for (vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
             vpn >= (int)MEM_INVALID_PAGES; vpn--) {
            if (!current_proc->pt0[vpn].valid) break;
            stack_base = vpn << PAGESHIFT;
        }

        /* Check if addr is between brk and current stack base, with room for red zone */
        if (addr < stack_base && addr >= brk_page + PAGESIZE) {
            /* Grow the stack down to cover addr */
            unsigned long new_stack_base = DOWN_TO_PAGE(addr);

            /* Ensure red zone between heap and stack */
            if (new_stack_base <= brk_page) {
                goto kill_proc;
            }

            for (page_addr = new_stack_base; page_addr < stack_base; page_addr += PAGESIZE) {
                vpn = page_addr >> PAGESHIFT;
                int pfn = alloc_frame();
                if (pfn < 0) goto kill_proc;

                current_proc->pt0[vpn].valid = 1;
                current_proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn].pfn = pfn;
            }
            current_proc->user_stack_base = (void *)new_stack_base;
            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
            return;
        }
    }

kill_proc:
    TracePrintf(0, "TRAP_MEMORY: Process %d terminated (addr %p, code %d)\n",
                current_proc->pid, info->addr, info->code);
    fprintf(stderr, "Process %d terminated: memory exception at %p\n",
            current_proc->pid, info->addr);
    kern_exit(ERROR, info);
}

static void
trap_math(ExceptionInfo *info)
{
    TracePrintf(0, "TRAP_MATH: Process %d terminated (math error, code %d)\n",
                current_proc->pid, info->code);
    fprintf(stderr, "Process %d terminated: math error\n", current_proc->pid);
    kern_exit(ERROR, info);
}

static void
trap_tty_receive(ExceptionInfo *info)
{
    int tty_id = info->code;
    tty_buf_t *buf;

    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;

    /* Allocate a buffer and read the line */
    buf = (tty_buf_t *)malloc(sizeof(tty_buf_t));
    if (!buf) return;

    buf->len = TtyReceive(tty_id, buf->data, TERMINAL_MAX_LINE);
    buf->offset = 0;
    buf->next = NULL;

    /* Add to the input buffer queue for this terminal */
    if (!tty_read_bufs[tty_id]) {
        tty_read_bufs[tty_id] = buf;
    } else {
        tty_buf_t *last = tty_read_bufs[tty_id];
        while (last->next) last = last->next;
        last->next = buf;
    }

    /* Wake up blocked reader if any */
    if (tty_read_blocked[tty_id]) {
        pcb_t *p = tty_read_blocked[tty_id];
        tty_read_blocked[tty_id] = p->next;
        p->next = NULL;
        enqueue_ready(p);
    }
}

static void
trap_tty_transmit(ExceptionInfo *info)
{
    int tty_id = info->code;

    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;

    /* Unblock the process that was writing */
    pcb_t *done = tty_write_active[tty_id];
    tty_write_active[tty_id] = NULL;

    if (done) {
        enqueue_ready(done);
    }

    /* Start next pending write if any */
    if (tty_write_queue[tty_id]) {
        pcb_t *next_writer = tty_write_queue[tty_id];
        tty_write_queue[tty_id] = next_writer->next;
        next_writer->next = NULL;
        tty_write_active[tty_id] = next_writer;

        /* The write data was saved previously; re-transmit.
         * We stored the length in delay_ticks temporarily for writes. */
        TtyTransmit(tty_id, tty_xmit_buf[tty_id], next_writer->delay_ticks);
    }
}

/* ========================================================================
 * Kernel Call Implementations
 * ======================================================================== */

static int
kern_fork(ExceptionInfo *info)
{
    pcb_t *child;
    int i, pfn;

    /* Count pages needed for child */
    int pages_needed = 0;
    for (i = 0; i < (int)(KERNEL_STACK_BASE >> PAGESHIFT); i++) {
        if (current_proc->pt0[i].valid) pages_needed++;
    }
    /* Add kernel stack pages */
    pages_needed += KERNEL_STACK_PAGES;

    if (pages_needed > free_frame_count) return ERROR;

    child = create_pcb();
    if (!child) return ERROR;

    /* Set up parent-child relationship */
    child->parent = current_proc;
    child->sibling = current_proc->children;
    current_proc->children = child;

    /* Copy user-space page table entries and physical pages */
    child->brk = current_proc->brk;
    child->user_stack_base = current_proc->user_stack_base;

    /* Use a temp page in Region 1 for copying */
    int temp_vpn = (VMEM_1_BASE >> PAGESHIFT) + PAGE_TABLE_LEN - 1;
    int temp_idx = PAGE_TABLE_LEN - 1;
    struct pte saved_pte = kernel_pt1[temp_idx];

    for (i = 0; i < (int)(KERNEL_STACK_BASE >> PAGESHIFT); i++) {
        if (current_proc->pt0[i].valid) {
            pfn = alloc_frame();
            if (pfn < 0) {
                /* Cleanup and fail */
                kernel_pt1[temp_idx] = saved_pte;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));
                destroy_process(child);
                return ERROR;
            }
            child->pt0[i] = current_proc->pt0[i];
            child->pt0[i].pfn = pfn;

            /* Map child's frame temporarily in Region 1 */
            kernel_pt1[temp_idx].valid = 1;
            kernel_pt1[temp_idx].kprot = PROT_READ | PROT_WRITE;
            kernel_pt1[temp_idx].uprot = PROT_NONE;
            kernel_pt1[temp_idx].pfn = pfn;
            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));

            memcpy((void *)(temp_vpn << PAGESHIFT),
                   (void *)(i << PAGESHIFT),
                   PAGESIZE);
        }
    }

    /* Restore temp page */
    kernel_pt1[temp_idx] = saved_pte;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));

    /* Copy kernel stack and get SavedContext via ContextSwitch */
    child->state = PROC_READY;
    ContextSwitch(ForkSwitchFunc, &current_proc->ctx,
                  (void *)current_proc, (void *)child);

    /* After returning from ContextSwitch, check who we are */
    if (current_proc->pid == child->pid) {
        /* We are the child — return 0 */
        return 0;
    }

    /* We are the parent — enqueue child and return child pid */
    enqueue_ready(child);
    return child->pid;
}

static int
kern_exec(char *filename, char **argvec, ExceptionInfo *info)
{
    int rc;

    /* Validate filename pointer */
    if (validate_user_string(current_proc, filename) < 0) return ERROR;

    /* Validate argvec - it's an array of pointers terminated by NULL */
    if (!argvec) return ERROR;
    {
        int i;
        unsigned long av_addr = (unsigned long)argvec;
        for (i = 0; ; i++) {
            /* Validate that we can read this pointer */
            if (validate_user_buf(current_proc, &argvec[i], sizeof(char *), 0) < 0)
                return ERROR;
            if (argvec[i] == NULL) break;
            if (validate_user_string(current_proc, argvec[i]) < 0)
                return ERROR;
        }
        (void)av_addr;
    }

    rc = LoadProgram(filename, argvec, current_proc, info);
    if (rc == 0) {
        /* Success — LoadProgram updated info->pc and info->sp */
        return 0;  /* But Exec doesn't "return" on success per se */
    }
    if (rc == -2) {
        /* Process is no longer runnable */
        kern_exit(ERROR, info);
        /* Does not return */
    }
    return ERROR;
}

static void
kern_exit(int status, ExceptionInfo *info)
{
    pcb_t *parent = current_proc->parent;
    int any_remaining = 0;
    int i;

    TracePrintf(1, "Process %d exiting with status %d\n", current_proc->pid, status);

    /* Free all user-space pages (not kernel stack yet - we're using it) */
    for (i = 0; i < (int)(KERNEL_STACK_BASE >> PAGESHIFT); i++) {
        if (current_proc->pt0[i].valid) {
            free_frame(current_proc->pt0[i].pfn);
            current_proc->pt0[i].valid = 0;
        }
    }

    /* Handle children - orphan them */
    {
        pcb_t *child = current_proc->children;
        while (child) {
            pcb_t *next_sib = child->sibling;
            child->parent = NULL;
            child->sibling = NULL;
            if (child->state == PROC_ZOMBIE) {
                /* Free zombie child with no parent */
                /* Free its kernel stack */
                int j;
                for (j = 0; j < KERNEL_STACK_PAGES; j++) {
                    int ksvpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
                    if (child->pt0[ksvpn].valid) {
                        free_frame(child->pt0[ksvpn].pfn);
                        child->pt0[ksvpn].valid = 0;
                    }
                }
                proc_table[child->pid] = NULL;
                free(child->pt0);
                free(child);
            }
            child = next_sib;
        }
        current_proc->children = NULL;
    }

    /* Also free zombie queue */
    {
        pcb_t *z = current_proc->zombie_head;
        while (z) {
            pcb_t *nz = z->zombie_next;
            int j;
            for (j = 0; j < KERNEL_STACK_PAGES; j++) {
                int ksvpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
                if (z->pt0[ksvpn].valid) {
                    free_frame(z->pt0[ksvpn].pfn);
                    z->pt0[ksvpn].valid = 0;
                }
            }
            proc_table[z->pid] = NULL;
            free(z->pt0);
            free(z);
            z = nz;
        }
        current_proc->zombie_head = NULL;
        current_proc->zombie_tail = NULL;
    }

    if (parent) {
        /* Become a zombie - parent may Wait for us */
        current_proc->exit_status = status;
        current_proc->state = PROC_ZOMBIE;

        /* Remove from parent's active children list */
        pcb_t **pp = &parent->children;
        while (*pp) {
            if (*pp == current_proc) {
                *pp = current_proc->sibling;
                break;
            }
            pp = &(*pp)->sibling;
        }
        current_proc->sibling = NULL;

        /* Add to parent's zombie queue */
        current_proc->zombie_next = NULL;
        if (parent->zombie_tail) {
            parent->zombie_tail->zombie_next = current_proc;
        } else {
            parent->zombie_head = current_proc;
        }
        parent->zombie_tail = current_proc;

        /* Wake up parent if it's blocked in Wait */
        if (parent->state == PROC_BLOCKED_WAIT) {
            parent->state = PROC_READY;
            enqueue_ready(parent);
        }
    } else {
        /* Orphan - no parent to collect status, free kernel stack */
        int j;
        for (j = 0; j < KERNEL_STACK_PAGES; j++) {
            int ksvpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
            if (current_proc->pt0[ksvpn].valid) {
                free_frame(current_proc->pt0[ksvpn].pfn);
                current_proc->pt0[ksvpn].valid = 0;
            }
        }
        proc_table[current_proc->pid] = NULL;
        free(current_proc->pt0);
        free(current_proc);
    }

    /* Check if any processes remain (besides idle) */
    for (i = 1; i < MAX_PROCESSES; i++) {
        if (proc_table[i] && proc_table[i]->state != PROC_ZOMBIE) {
            any_remaining = 1;
            break;
        }
    }
    /* Also check ready queue and delay queue */
    if (ready_head) any_remaining = 1;

    if (!any_remaining) {
        TracePrintf(0, "No more processes. Halting.\n");
        fprintf(stderr, "All processes have exited. Halting Yalnix.\n");
        Halt();
    }

    /* Switch to next process */
    current_proc = idle_proc;  /* Temporarily become idle */
    schedule(info);

    /* If we get here, we're now running as some other process */
}

static int
kern_wait(int *status_ptr, ExceptionInfo *info)
{
    pcb_t *zombie;

    /* Validate status_ptr */
    if (validate_user_buf(current_proc, status_ptr, sizeof(int), 1) < 0)
        return ERROR;

    /* Check if we have any children at all */
    if (!current_proc->children && !current_proc->zombie_head) return ERROR;

    /* Check for zombie children */
    if (current_proc->zombie_head) {
        zombie = current_proc->zombie_head;
        current_proc->zombie_head = zombie->zombie_next;
        if (!current_proc->zombie_head) current_proc->zombie_tail = NULL;

        *status_ptr = zombie->exit_status;
        int child_pid = zombie->pid;

        /* Free zombie's kernel stack */
        int j;
        for (j = 0; j < KERNEL_STACK_PAGES; j++) {
            int ksvpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
            if (zombie->pt0[ksvpn].valid) {
                free_frame(zombie->pt0[ksvpn].pfn);
                zombie->pt0[ksvpn].valid = 0;
            }
        }
        proc_table[zombie->pid] = NULL;
        free(zombie->pt0);
        free(zombie);

        return child_pid;
    }

    /* No zombies yet, block until a child exits */
    current_proc->state = PROC_BLOCKED_WAIT;
    schedule(info);

    /* When we wake up, there should be a zombie */
    if (current_proc->zombie_head) {
        zombie = current_proc->zombie_head;
        current_proc->zombie_head = zombie->zombie_next;
        if (!current_proc->zombie_head) current_proc->zombie_tail = NULL;

        *status_ptr = zombie->exit_status;
        int child_pid = zombie->pid;

        int j;
        for (j = 0; j < KERNEL_STACK_PAGES; j++) {
            int ksvpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
            if (zombie->pt0[ksvpn].valid) {
                free_frame(zombie->pt0[ksvpn].pfn);
                zombie->pt0[ksvpn].valid = 0;
            }
        }
        proc_table[zombie->pid] = NULL;
        free(zombie->pt0);
        free(zombie);

        return child_pid;
    }

    return ERROR;
}

static int
kern_getpid(void)
{
    return current_proc->pid;
}

static int
kern_brk(void *addr)
{
    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
    unsigned long old_brk = (unsigned long)UP_TO_PAGE(current_proc->brk);
    unsigned long stack_base = (unsigned long)current_proc->user_stack_base;
    unsigned long page;
    int vpn, pfn;

    if (new_brk < MEM_INVALID_SIZE) return ERROR;
    if (new_brk >= KERNEL_STACK_BASE) return ERROR;

    /* Ensure at least one page gap (red zone) between heap and stack */
    if (new_brk + PAGESIZE > stack_base) return ERROR;

    if (new_brk > old_brk) {
        /* Growing - allocate new pages */
        int pages_needed = (new_brk - old_brk) >> PAGESHIFT;
        if (pages_needed > free_frame_count) return ERROR;

        for (page = old_brk; page < new_brk; page += PAGESIZE) {
            vpn = page >> PAGESHIFT;
            if (!current_proc->pt0[vpn].valid) {
                pfn = alloc_frame();
                if (pfn < 0) return ERROR;
                current_proc->pt0[vpn].valid = 1;
                current_proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
                current_proc->pt0[vpn].pfn = pfn;
            }
        }
    } else if (new_brk < old_brk) {
        /* Shrinking - free pages */
        for (page = new_brk; page < old_brk; page += PAGESIZE) {
            vpn = page >> PAGESHIFT;
            if (current_proc->pt0[vpn].valid) {
                free_frame(current_proc->pt0[vpn].pfn);
                current_proc->pt0[vpn].valid = 0;
            }
        }
    }

    current_proc->brk = addr;
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    return 0;
}

static int
kern_delay(int ticks, ExceptionInfo *info)
{
    if (ticks < 0) return ERROR;
    if (ticks == 0) return 0;

    current_proc->delay_ticks = ticks;
    current_proc->state = PROC_BLOCKED_DELAY;

    /* Add to delay list */
    current_proc->next = delay_head;
    delay_head = current_proc;

    schedule(info);
    return 0;
}

static int
kern_ttyread(int tty_id, void *buf, int len, ExceptionInfo *info)
{
    tty_buf_t *tbuf;
    int copy_len;

    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
    if (len < 0) return ERROR;
    if (len == 0) return 0;
    if (validate_user_buf(current_proc, buf, len, 1) < 0) return ERROR;

    /* Wait for input if none available */
    while (!tty_read_bufs[tty_id]) {
        current_proc->state = PROC_BLOCKED_TTY_READ;
        current_proc->next = NULL;

        /* Add to blocked reader list */
        if (!tty_read_blocked[tty_id]) {
            tty_read_blocked[tty_id] = current_proc;
        } else {
            pcb_t *last = tty_read_blocked[tty_id];
            while (last->next) last = last->next;
            last->next = current_proc;
        }

        schedule(info);

        /* After waking up, check again */
    }

    /* Read from the input buffer */
    tbuf = tty_read_bufs[tty_id];
    copy_len = tbuf->len - tbuf->offset;
    if (copy_len > len) copy_len = len;

    memcpy(buf, tbuf->data + tbuf->offset, copy_len);
    tbuf->offset += copy_len;

    /* If we've consumed the entire buffer, free it */
    if (tbuf->offset >= tbuf->len) {
        tty_read_bufs[tty_id] = tbuf->next;
        free(tbuf);
    }

    return copy_len;
}

static int
kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info)
{
    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
    if (len < 0 || len > TERMINAL_MAX_LINE) return ERROR;
    if (len == 0) return 0;
    if (validate_user_buf(current_proc, buf, len, 0) < 0) return ERROR;

    /* Copy data to kernel buffer */
    memcpy(tty_xmit_buf[tty_id], buf, len);
    current_proc->delay_ticks = len; /* Reuse field to store write length */

    if (!tty_write_active[tty_id]) {
        /* Terminal is free, start transmitting */
        tty_write_active[tty_id] = current_proc;
        current_proc->state = PROC_BLOCKED_TTY_WRITE;
        TtyTransmit(tty_id, tty_xmit_buf[tty_id], len);
        schedule(info);
    } else {
        /* Terminal busy, queue this write */
        current_proc->state = PROC_BLOCKED_TTY_WRITE;
        current_proc->next = NULL;
        if (!tty_write_queue[tty_id]) {
            tty_write_queue[tty_id] = current_proc;
        } else {
            pcb_t *last = tty_write_queue[tty_id];
            while (last->next) last = last->next;
            last->next = current_proc;
        }
        schedule(info);
    }

    return len;
}

/* ========================================================================
 * LoadProgram
 * ======================================================================== */

static int
LoadProgram(char *name, char **args, pcb_t *proc, ExceptionInfo *info)
{
    int fd;
    int status;
    struct loadinfo li;
    char *cp;
    char *cp2;
    char **cpp;
    char *argbuf;
    int i;
    unsigned long argcount;
    int size;
    int text_npg;
    int data_bss_npg;
    int stack_npg;

    TracePrintf(0, "LoadProgram '%s', args %p\n", name, args);

    if ((fd = open(name, O_RDONLY)) < 0) {
        TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
        return (-1);
    }

    status = LoadInfo(fd, &li);
    TracePrintf(0, "LoadProgram: LoadInfo status %d\n", status);
    switch (status) {
    case LI_SUCCESS:
        break;
    case LI_FORMAT_ERROR:
        TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
        close(fd);
        return (-1);
    case LI_OTHER_ERROR:
        TracePrintf(0, "LoadProgram: '%s' other error\n", name);
        close(fd);
        return (-1);
    default:
        TracePrintf(0, "LoadProgram: '%s' unknown error\n", name);
        close(fd);
        return (-1);
    }
    TracePrintf(0, "text_size 0x%lx, data_size 0x%lx, bss_size 0x%lx\n",
                li.text_size, li.data_size, li.bss_size);
    TracePrintf(0, "entry 0x%lx\n", li.entry);

    size = 0;
    for (i = 0; args[i] != NULL; i++) {
        size += strlen(args[i]) + 1;
    }
    argcount = i;
    TracePrintf(0, "LoadProgram: size %d, argcount %d\n", size, (int)argcount);

    cp = argbuf = (char *)malloc(size);
    if (!argbuf) {
        close(fd);
        return (-1);
    }
    for (i = 0; args[i] != NULL; i++) {
        strcpy(cp, args[i]);
        cp += strlen(cp) + 1;
    }

    cp = ((char *)USER_STACK_LIMIT) - size;
    cpp = (char **)((unsigned long)cp & (-1 << 4));
    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));

    text_npg = li.text_size >> PAGESHIFT;
    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;

    TracePrintf(0, "LoadProgram: text_npg %d, data_bss_npg %d, stack_npg %d\n",
                text_npg, data_bss_npg, stack_npg);

    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
        TracePrintf(0, "LoadProgram: program '%s' size too large for VIRTUAL memory\n", name);
        free(argbuf);
        close(fd);
        return (-1);
    }

    /* Check physical memory: count pages currently used (that will be freed) */
    {
        int pages_to_free = 0;
        for (i = 0; i < (int)(KERNEL_STACK_BASE >> PAGESHIFT); i++) {
            if (proc->pt0[i].valid) pages_to_free++;
        }
        int pages_needed = text_npg + data_bss_npg + stack_npg;
        if (pages_needed - pages_to_free > free_frame_count) {
            TracePrintf(0, "LoadProgram: program '%s' size too large for PHYSICAL memory\n", name);
            free(argbuf);
            close(fd);
            return (-1);
        }
    }

    /* Set sp */
    info->sp = (void *)cpp;

    /* Free old Region 0 pages (except kernel stack) */
    for (i = 0; i < (int)(KERNEL_STACK_BASE >> PAGESHIFT); i++) {
        if (proc->pt0[i].valid) {
            free_frame(proc->pt0[i].pfn);
            proc->pt0[i].valid = 0;
        }
    }

    /* Leave first MEM_INVALID_PAGES PTEs invalid */

    /* Text pages */
    for (i = 0; i < text_npg; i++) {
        int vpn = MEM_INVALID_PAGES + i;
        int pfn = alloc_frame();
        proc->pt0[vpn].valid = 1;
        proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        proc->pt0[vpn].uprot = PROT_READ | PROT_EXEC;
        proc->pt0[vpn].pfn = pfn;
    }

    /* Data+BSS pages */
    for (i = 0; i < data_bss_npg; i++) {
        int vpn = MEM_INVALID_PAGES + text_npg + i;
        int pfn = alloc_frame();
        proc->pt0[vpn].valid = 1;
        proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
        proc->pt0[vpn].pfn = pfn;
    }

    /* Stack pages */
    for (i = 0; i < stack_npg; i++) {
        int vpn = (USER_STACK_LIMIT >> PAGESHIFT) - stack_npg + i;
        int pfn = alloc_frame();
        proc->pt0[vpn].valid = 1;
        proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
        proc->pt0[vpn].pfn = pfn;
    }

    /* Set process break and stack base */
    proc->brk = (void *)((MEM_INVALID_PAGES + text_npg + data_bss_npg) << PAGESHIFT);
    proc->user_stack_base = (void *)((USER_STACK_LIMIT >> PAGESHIFT) - stack_npg << PAGESHIFT);

    /* Flush TLB */
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /* Read text and data from file */
    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
        != (ssize_t)(li.text_size + li.data_size)) {
        TracePrintf(0, "LoadProgram: couldn't read for '%s'\n", name);
        free(argbuf);
        close(fd);
        return (-2);
    }

    close(fd);

    /* Set text pages to read/execute only */
    for (i = 0; i < text_npg; i++) {
        int vpn = MEM_INVALID_PAGES + i;
        proc->pt0[vpn].kprot = PROT_READ | PROT_EXEC;
    }

    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /* Zero out BSS */
    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
           '\0', li.bss_size);

    /* Set entry point */
    info->pc = (void *)li.entry;

    /* Build argument list on new stack */
    *cpp++ = (char *)argcount;
    cp2 = argbuf;
    for (i = 0; (unsigned long)i < argcount; i++) {
        *cpp++ = cp;
        strcpy(cp, cp2);
        cp += strlen(cp) + 1;
        cp2 += strlen(cp2) + 1;
    }
    free(argbuf);
    *cpp++ = NULL;
    *cpp++ = NULL;
    *cpp++ = 0;

    /* Initialize registers to 0 */
    for (i = 0; i < NUM_REGS; i++) {
        info->regs[i] = 0;
    }
    info->psr = 0;

    return (0);
}

/* ========================================================================
 * SetKernelBrk
 * ======================================================================== */

int
SetKernelBrk(void *addr)
{
    if (!vm_enabled) {
        /* Before VM, just track the break */
        kernel_brk = addr;
        return 0;
    }

    /* After VM is enabled, allocate/free pages as needed */
    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
    unsigned long old_brk = (unsigned long)UP_TO_PAGE(kernel_brk);
    unsigned long page;

    if (new_brk > old_brk) {
        /* Growing — allocate new pages */
        for (page = old_brk; page < new_brk; page += PAGESIZE) {
            int vpn1 = (page - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn1 < 0 || vpn1 >= PAGE_TABLE_LEN) return -1;
            if (!kernel_pt1[vpn1].valid) {
                int pfn = alloc_frame();
                if (pfn < 0) return -1;
                kernel_pt1[vpn1].valid = 1;
                kernel_pt1[vpn1].kprot = PROT_READ | PROT_WRITE;
                kernel_pt1[vpn1].uprot = PROT_NONE;
                kernel_pt1[vpn1].pfn = pfn;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
            }
        }
    } else if (new_brk < old_brk) {
        /* Shrinking — free pages */
        for (page = new_brk; page < old_brk; page += PAGESIZE) {
            int vpn1 = (page - VMEM_1_BASE) >> PAGESHIFT;
            if (vpn1 >= 0 && vpn1 < PAGE_TABLE_LEN && kernel_pt1[vpn1].valid) {
                free_frame(kernel_pt1[vpn1].pfn);
                kernel_pt1[vpn1].valid = 0;
                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)page);
            }
        }
    }

    kernel_brk = addr;
    return 0;
}

/* ========================================================================
 * KernelStart
 * ======================================================================== */

void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    int i;
    int num_phys_pages;
    unsigned long kernel_text_end;
    unsigned long kernel_data_end;

    TracePrintf(0, "KernelStart: pmem_size=%u, orig_brk=%p\n", pmem_size, orig_brk);

    kernel_brk = orig_brk;
    kernel_brk_init = orig_brk;

    /* ---- 1. Initialize interrupt vector table ---- */
    for (i = 0; i < TRAP_VECTOR_SIZE; i++) {
        interrupt_vector[i] = NULL;
    }
    interrupt_vector[TRAP_KERNEL] = trap_kernel;
    interrupt_vector[TRAP_CLOCK] = trap_clock;
    interrupt_vector[TRAP_ILLEGAL] = trap_illegal;
    interrupt_vector[TRAP_MEMORY] = trap_memory;
    interrupt_vector[TRAP_MATH] = trap_math;
    interrupt_vector[TRAP_TTY_RECEIVE] = trap_tty_receive;
    interrupt_vector[TRAP_TTY_TRANSMIT] = trap_tty_transmit;

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)interrupt_vector);

    /* ---- 2. Set up free frame list ---- */
    num_phys_pages = pmem_size / PAGESIZE;
    total_frames = num_phys_pages;
    free_frames = (int *)malloc(num_phys_pages * sizeof(int));
    free_frame_count = 0;

    /* Figure out what physical memory is in use by the kernel.
     * The kernel occupies physical memory from VMEM_1_BASE to kernel_brk. */
    kernel_text_end = (unsigned long)UP_TO_PAGE(&_etext);
    kernel_data_end = (unsigned long)UP_TO_PAGE(kernel_brk);

    /* Mark kernel-used pages and put the rest on free list.
     * Kernel is loaded at physical address VMEM_1_BASE.
     * Kernel text: VMEM_1_BASE to &_etext
     * Kernel data/heap: &_etext to kernel_brk
     * Kernel stack (initial process): at top of Region 0, physical addr same as virtual
     */
    {
        int kernel_base_pfn = VMEM_1_BASE >> PAGESHIFT;
        int kernel_top_pfn = (unsigned long)UP_TO_PAGE(kernel_brk) >> PAGESHIFT;
        /* Initial kernel stack is at KERNEL_STACK_BASE physical */
        int kstack_base_pfn = KERNEL_STACK_BASE >> PAGESHIFT;
        int kstack_top_pfn = KERNEL_STACK_LIMIT >> PAGESHIFT;

        for (i = 0; i < num_phys_pages; i++) {
            /* Skip pages used by kernel text/data/heap */
            if (i >= kernel_base_pfn && i < kernel_top_pfn) continue;
            /* Skip pages used by initial kernel stack */
            if (i >= kstack_base_pfn && i < kstack_top_pfn) continue;
            /* This page is free */
            free_frames[free_frame_count++] = i;
        }
    }

    TracePrintf(0, "KernelStart: %d free frames out of %d total\n",
                free_frame_count, num_phys_pages);

    /* ---- 3. Build initial page tables ---- */

    /* Allocate Region 1 page table. We need it page-aligned.
     * Since we haven't enabled VM yet, addresses are physical.
     * We'll place it in the kernel heap area. */
    {
        /* We need PAGE_TABLE_SIZE bytes for the Region 1 page table.
         * Allocate from the current kernel break. */
        unsigned long pt1_addr = (unsigned long)UP_TO_PAGE(kernel_brk);
        kernel_pt1 = (struct pte *)pt1_addr;
        kernel_pt1_phys = pt1_addr;
        kernel_brk = (void *)(pt1_addr + PAGE_TABLE_SIZE);
        memset(kernel_pt1, 0, PAGE_TABLE_SIZE);
    }

    /* Allocate Region 0 page table for the initial process */
    struct pte *init_pt0;
    unsigned long init_pt0_phys;
    {
        unsigned long pt0_addr = (unsigned long)UP_TO_PAGE(kernel_brk);
        init_pt0 = (struct pte *)pt0_addr;
        init_pt0_phys = pt0_addr;
        kernel_brk = (void *)(pt0_addr + PAGE_TABLE_SIZE);
        memset(init_pt0, 0, PAGE_TABLE_SIZE);
    }

    /* Remove the page table pages from the free list (they were just allocated from
     * beyond the original kernel_brk, so they might be in the free list) */
    /* Actually, we need to re-mark the free list now that kernel_brk has moved */
    {
        free_frame_count = 0;
        int kernel_base_pfn = VMEM_1_BASE >> PAGESHIFT;
        int kernel_top_pfn = (unsigned long)UP_TO_PAGE(kernel_brk) >> PAGESHIFT;
        int kstack_base_pfn = KERNEL_STACK_BASE >> PAGESHIFT;
        int kstack_top_pfn = KERNEL_STACK_LIMIT >> PAGESHIFT;

        for (i = 0; i < num_phys_pages; i++) {
            if (i >= kernel_base_pfn && i < kernel_top_pfn) continue;
            if (i >= kstack_base_pfn && i < kstack_top_pfn) continue;
            free_frames[free_frame_count++] = i;
        }
    }

    /* Build Region 1 page table entries */
    kernel_text_end = (unsigned long)UP_TO_PAGE(&_etext);
    kernel_data_end = (unsigned long)UP_TO_PAGE(kernel_brk);

    for (i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long vaddr = VMEM_1_BASE + (i << PAGESHIFT);
        unsigned long paddr = vaddr; /* Identity mapping for kernel */

        if (vaddr >= VMEM_1_BASE && vaddr < kernel_text_end) {
            /* Kernel text */
            kernel_pt1[i].valid = 1;
            kernel_pt1[i].kprot = PROT_READ | PROT_EXEC;
            kernel_pt1[i].uprot = PROT_NONE;
            kernel_pt1[i].pfn = paddr >> PAGESHIFT;
        } else if (vaddr >= kernel_text_end && vaddr < kernel_data_end) {
            /* Kernel data/bss/heap */
            kernel_pt1[i].valid = 1;
            kernel_pt1[i].kprot = PROT_READ | PROT_WRITE;
            kernel_pt1[i].uprot = PROT_NONE;
            kernel_pt1[i].pfn = paddr >> PAGESHIFT;
        } else {
            kernel_pt1[i].valid = 0;
        }
    }

    /* Build Region 0 page table - only kernel stack for now */
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + i;
        unsigned long paddr = vpn << PAGESHIFT; /* Identity mapping */
        init_pt0[vpn].valid = 1;
        init_pt0[vpn].kprot = PROT_READ | PROT_WRITE;
        init_pt0[vpn].uprot = PROT_NONE;
        init_pt0[vpn].pfn = paddr >> PAGESHIFT;
    }

    /* ---- 4. Set page table registers and enable VM ---- */
    WriteRegister(REG_PTR0, (RCS421RegVal)init_pt0_phys);
    WriteRegister(REG_PTR1, (RCS421RegVal)kernel_pt1_phys);
    WriteRegister(REG_VM_ENABLE, 1);
    vm_enabled = 1;

    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_ALL);

    TracePrintf(0, "KernelStart: Virtual memory enabled\n");

    /* After VM is enabled, kernel_pt1 and init_pt0 are now accessible
     * via their virtual addresses (which happen to be the same as physical
     * due to identity mapping). */

    /* ---- 5. Initialize TTY state ---- */
    for (i = 0; i < NUM_TERMINALS; i++) {
        tty_read_bufs[i] = NULL;
        tty_read_blocked[i] = NULL;
        tty_write_active[i] = NULL;
        tty_write_queue[i] = NULL;
    }

    /* ---- 6. Create idle process (PID 0) ---- */
    idle_proc = (pcb_t *)malloc(sizeof(pcb_t));
    memset(idle_proc, 0, sizeof(pcb_t));
    idle_proc->pid = next_pid++;  /* PID 0 */
    idle_proc->state = PROC_READY;
    idle_proc->pt0 = init_pt0;
    idle_proc->pt0_phys = init_pt0_phys;
    proc_table[0] = idle_proc;

    current_proc = idle_proc;

    /* The idle process will just loop with Pause. We'll set it up so that
     * the current context becomes the idle process context. */
    ContextSwitch(InitIdleSwitchFunc, &idle_proc->ctx, (void *)idle_proc, NULL);

    /* ---- 7. Create init process (PID 1) ---- */
    {
        pcb_t *init_proc = create_pcb();
        if (!init_proc) {
            TracePrintf(0, "KernelStart: Failed to create init process\n");
            Halt();
        }

        /* Determine the init program name */
        char *init_name = "init";
        char **init_args;
        if (cmd_args && cmd_args[0]) {
            init_name = cmd_args[0];
            init_args = cmd_args;
        } else {
            static char *default_args[] = { "init", NULL };
            init_args = default_args;
        }

        /* Switch to init's Region 0 to load the program */
        WriteRegister(REG_PTR0, init_proc->pt0_phys);
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

        int rc = LoadProgram(init_name, init_args, init_proc, info);
        if (rc != 0) {
            TracePrintf(0, "KernelStart: Failed to load init program '%s'\n", init_name);
            /* Switch back to idle and halt */
            WriteRegister(REG_PTR0, idle_proc->pt0_phys);
            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
            Halt();
        }

        init_proc->state = PROC_RUNNING;
        current_proc = init_proc;

        TracePrintf(0, "KernelStart: Init process loaded, returning to user mode\n");
    }

    /* When KernelStart returns, the hardware will use the ExceptionInfo values
     * to set up user mode execution of the init process. */
}

