211→ * Context Switching
212→ * ======================================================================== */
213→
214→static SavedContext *
215→MySwitchFunc(SavedContext *ctxp, void *p1, void *p2)
216→{
217→    pcb_t *old = (pcb_t *)p1;
218→    pcb_t *new = (pcb_t *)p2;
219→
220→    /* Save context in old PCB */
221→    old->ctx = *ctxp;
222→
223→    /* Switch Region 0 page table */
224→    WriteRegister(REG_PTR0, new->pt0_phys);
225→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
226→
227→    return &new->ctx;
228→}
229→
230→static SavedContext *
231→ForkSwitchFunc(SavedContext *ctxp, void *p1, void *p2)
232→{
233→    pcb_t *parent = (pcb_t *)p1;
234→    pcb_t *child = (pcb_t *)p2;
235→    int i;
236→
237→    /* Save context in both parent and child */
238→    parent->ctx = *ctxp;
239→    child->ctx = *ctxp;
240→
241→    /* Copy kernel stack pages from parent to child.
242→     * We use a temporary mapping in Region 1 to write to child's physical pages.
243→     * We'll use the page just above the current kernel break for temp mapping.
244→     */
245→    unsigned long temp_vpn = (VMEM_1_BASE >> PAGESHIFT) + PAGE_TABLE_LEN - 1; /* Use last Region 1 page */
246→    int temp_idx = PAGE_TABLE_LEN - 1;
247→
248→    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
249→        int src_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + i;
250→        int child_pfn = child->pt0[src_vpn].pfn;
251→
252→        /* Temporarily map child's physical page into Region 1 */
253→        struct pte old_pte = kernel_pt1[temp_idx];
254→        kernel_pt1[temp_idx].valid = 1;
255→        kernel_pt1[temp_idx].kprot = PROT_READ | PROT_WRITE;
256→        kernel_pt1[temp_idx].uprot = PROT_NONE;
257→        kernel_pt1[temp_idx].pfn = child_pfn;
258→        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(temp_vpn << PAGESHIFT));
259→
260→        /* Copy from parent's kernel stack to temp-mapped child page */
261→        memcpy((void *)((unsigned long)temp_vpn << PAGESHIFT),
262→               (void *)((unsigned long)src_vpn << PAGESHIFT),
263→               PAGESIZE);
264→
265→        /* Restore old mapping */
266→        kernel_pt1[temp_idx] = old_pte;
267→        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)((unsigned long)temp_vpn << PAGESHIFT));
268→    }
269→
270→    /* Stay on parent's Region 0 — don't switch */
271→    return &parent->ctx;
272→}
