330→    unsigned long start = (unsigned long)buf;
331→    unsigned long end = start + len;
332→    unsigned long page_start, vpn;
333→
334→    if (len == 0) return 0;
335→    if (start >= VMEM_0_LIMIT || end > VMEM_0_LIMIT) return -1;
336→    if (start >= KERNEL_STACK_BASE) return -1;  /* Can't access kernel stack */
337→
338→    for (page_start = DOWN_TO_PAGE(start); page_start < end; page_start += PAGESIZE) {
339→        vpn = page_start >> PAGESHIFT;
340→        if (vpn >= PAGE_TABLE_LEN) return -1;
341→        if (!proc->pt0[vpn].valid) return -1;
342→        if (need_write && !(proc->pt0[vpn].uprot & PROT_WRITE)) return -1;
343→        if (!need_write && !(proc->pt0[vpn].uprot & PROT_READ)) return -1;
344→    }
345→    return 0;
346→}
