348→static int
349→validate_user_string(pcb_t *proc, char *str)
350→{
351→    unsigned long addr = (unsigned long)str;
352→    unsigned long vpn;
353→
354→    if (addr >= VMEM_0_LIMIT || addr >= KERNEL_STACK_BASE) return -1;
355→
356→    while (1) {
357→        vpn = addr >> PAGESHIFT;
358→        if (vpn >= PAGE_TABLE_LEN) return -1;
359→        if (!proc->pt0[vpn].valid) return -1;
360→        if (!(proc->pt0[vpn].uprot & PROT_READ)) return -1;
361→        if (*(char *)addr == '\0') return 0;
362→        addr++;
363→        if (addr >= VMEM_0_LIMIT || addr >= KERNEL_STACK_BASE) return -1;
364→    }
365→}
