368→ * Process Creation/Destruction
369→ * ======================================================================== */
370→
371→static pcb_t *
372→create_pcb(void)
373→{
374→    pcb_t *p;
375→    int i, pfn;
376→
377→    if (next_pid >= MAX_PROCESSES) return NULL;
378→
379→    p = (pcb_t *)malloc(sizeof(pcb_t));
380→    if (!p) return NULL;
381→    memset(p, 0, sizeof(pcb_t));
382→
383→    p->pid = next_pid++;
384→    p->state = PROC_FREE;
385→
386→    /* Allocate Region 0 page table - needs to be page-aligned and contiguous.
387→     * PAGE_TABLE_SIZE is the size of a page table.
388→     * We allocate a frame for the page table itself.
389→     */
390→    p->pt0 = (struct pte *)malloc(PAGE_TABLE_SIZE);
391→    if (!p->pt0) {
392→        free(p);
393→        return NULL;
394→    }
395→    memset(p->pt0, 0, PAGE_TABLE_SIZE);
396→
397→    /* We need the physical address of pt0. Since it's in Region 1 (kernel heap),
398→     * we can look up its physical address through the Region 1 page table. */
399→    {

400→        unsigned long vaddr = (unsigned long)p->pt0;
401→        unsigned long vpn1 = (vaddr - VMEM_1_BASE) >> PAGESHIFT;
402→        unsigned long offset = vaddr & PAGEOFFSET;
403→        p->pt0_phys = (kernel_pt1[vpn1].pfn << PAGESHIFT) + offset;
404→    }
405→
406→    /* Allocate kernel stack pages */
407→    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
408→        pfn = alloc_frame();
409→        if (pfn < 0) {
410→            /* Free already allocated pages */
411→            int j;
412→            for (j = 0; j < i; j++) {
413→                int kstack_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + j;
414→                free_frame(p->pt0[kstack_vpn].pfn);
415→            }
416→            free(p->pt0);
417→            free(p);
418→            return NULL;
419→        }
420→        int kstack_vpn = (KERNEL_STACK_BASE >> PAGESHIFT) + i;
421→        p->pt0[kstack_vpn].valid = 1;
422→        p->pt0[kstack_vpn].kprot = PROT_READ | PROT_WRITE;
423→        p->pt0[kstack_vpn].uprot = PROT_NONE;
424→        p->pt0[kstack_vpn].pfn = pfn;
425→    }
426→
427→    proc_table[p->pid] = p;
428→    return p;
429→}
430→
431→static void
432→destroy_process(pcb_t *p)
433→{
434→    int i;
435→
436→    /* Free all valid Region 0 pages */
437→    for (i = 0; i < PAGE_TABLE_LEN; i++) {
438→        if (p->pt0[i].valid) {
439→            free_frame(p->pt0[i].pfn);
440→            p->pt0[i].valid = 0;
441→        }
442→    }
443→
444→    /* Remove from parent's children list */
445→    if (p->parent) {
446→        pcb_t **pp = &p->parent->children;
447→        while (*pp) {
448→            if (*pp == p) {
449→                *pp = p->sibling;
450→                break;
451→            }
452→            pp = &(*pp)->sibling;
453→        }
454→    }
455→
456→    /* Orphan all children */
457→    {
458→        pcb_t *child = p->children;
459→        while (child) {
460→            pcb_t *next_child = child->sibling;
461→            child->parent = NULL;
462→            child->sibling = NULL;
463→            /* If child is zombie with no parent, free it */
464→            if (child->state == PROC_ZOMBIE) {
465→                proc_table[child->pid] = NULL;
466→                free(child->pt0);
467→                free(child);
468→            }
469→            child = next_child;
470→        }
471→    }
472→
473→    /* Free zombie children */
474→    {
475→        pcb_t *z = p->zombie_head;
476→        while (z) {
477→            pcb_t *next_z = z->zombie_next;
478→            proc_table[z->pid] = NULL;
479→            free(z->pt0);
480→            free(z);
481→            z = next_z;
482→        }
483→    }
484→
485→    proc_table[p->pid] = NULL;
486→    free(p->pt0);
487→    free(p);
488→}
