494→static void
495→trap_kernel(ExceptionInfo *info)
496→{
497→    int call_num = info->code;
498→    int rc;
499→

500→    switch (call_num) {
501→    case YALNIX_FORK:
502→        rc = kern_fork(info);
503→        info->regs[0] = rc;
504→        break;
505→    case YALNIX_EXEC:
506→        rc = kern_exec((char *)info->regs[1], (char **)info->regs[2], info);
507→        info->regs[0] = rc;
508→        break;
509→    case YALNIX_EXIT:
510→        kern_exit((int)info->regs[1], info);
511→        /* Does not return for this process */
512→        break;
513→    case YALNIX_WAIT:
514→        rc = kern_wait((int *)info->regs[1], info);
515→        info->regs[0] = rc;
516→        break;
517→    case YALNIX_GETPID:
518→        info->regs[0] = kern_getpid();
519→        break;
520→    case YALNIX_BRK:
521→        rc = kern_brk((void *)info->regs[1]);
522→        info->regs[0] = rc;
523→        break;
524→    case YALNIX_DELAY:
525→        rc = kern_delay((int)info->regs[1], info);
526→        info->regs[0] = rc;
527→        break;
528→    case YALNIX_TTY_READ:
529→        rc = kern_ttyread((int)info->regs[1], (void *)info->regs[2],
530→                          (int)info->regs[3], info);
531→        info->regs[0] = rc;
532→        break;
533→    case YALNIX_TTY_WRITE:
534→        fprintf(stderr, "DBG: TTY_WRITE tty=%d len=%d\n", (int)info->regs[1], (int)info->regs[3]);
535→        rc = kern_ttywrite((int)info->regs[1], (void *)info->regs[2],
536→                           (int)info->regs[3], info);
537→        fprintf(stderr, "DBG: TTY_WRITE returned rc=%d\n", rc);
538→        info->regs[0] = rc;
539→        break;
540→    default:
541→        TracePrintf(0, "Unknown kernel call %d from pid %d\n",
542→                    call_num, current_proc->pid);
543→        info->regs[0] = ERROR;
544→        break;
545→    }
546→}
