548→static void
549→trap_clock(ExceptionInfo *info)
550→{
551→    TracePrintf(0, "TRAP_CLOCK: current_proc pid=%d\n", current_proc->pid);
552→    /* Decrement delay counters */
553→    pcb_t *prev = NULL;
554→    pcb_t *p = delay_head;
555→
556→    while (p) {
557→        p->delay_ticks--;
558→        pcb_t *next = p->next;
559→        if (p->delay_ticks <= 0) {
560→            /* Remove from delay list */
561→            if (prev) prev->next = next;
562→            else delay_head = next;
563→            enqueue_ready(p);
564→        } else {
565→            prev = p;
566→        }
567→        p = next;
568→    }
569→
570→    /* Round-robin scheduling */
571→    if (current_proc != idle_proc) {
572→        current_proc->clock_ticks++;
573→        if (current_proc->clock_ticks >= CLOCK_QUANTUM && ready_head != NULL) {
574→            enqueue_ready(current_proc);
575→            schedule(info);
576→        }
577→    } else {
578→        /* Idle process running, switch if something is ready */
579→        if (ready_head != NULL) {
580→            schedule(info);
581→        }
582→    }
583→}
