588→    TracePrintf(0, "TRAP_ILLEGAL: Process %d terminated (illegal instruction at %p)\n",
589→                current_proc->pid, info->pc);
590→    fprintf(stderr, "Process %d terminated: illegal instruction\n", current_proc->pid);
591→    kern_exit(ERROR, info);
