594→static void
595→trap_memory(ExceptionInfo *info)
596→{
597→    unsigned long addr = (unsigned long)info->addr;
598→
599→    /* Check if this is a stack growth request */
600→    if (addr < VMEM_0_LIMIT && addr >= MEM_INVALID_SIZE) {
601→        unsigned long brk_page = (unsigned long)UP_TO_PAGE(current_proc->brk);
602→        unsigned long stack_base;
603→        unsigned long page_addr;
604→        int vpn;
605→
606→        /* Find current bottom of user stack */
607→        stack_base = (unsigned long)USER_STACK_LIMIT;
608→        for (vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
609→             vpn >= (int)MEM_INVALID_PAGES; vpn--) {
610→            if (!current_proc->pt0[vpn].valid) break;
611→            stack_base = vpn << PAGESHIFT;
612→        }
613→
614→        /* Check if addr is between brk and current stack base, with room for red zone */
615→        if (addr < stack_base && addr >= brk_page + PAGESIZE) {
616→            /* Grow the stack down to cover addr */
617→            unsigned long new_stack_base = DOWN_TO_PAGE(addr);
618→
619→            /* Ensure red zone between heap and stack */

620→            if (new_stack_base <= brk_page) {
621→                goto kill_proc;
622→            }
623→
624→            for (page_addr = new_stack_base; page_addr < stack_base; page_addr += PAGESIZE) {
625→                vpn = page_addr >> PAGESHIFT;
626→                int pfn = alloc_frame();
627→                if (pfn < 0) goto kill_proc;
628→
629→                current_proc->pt0[vpn].valid = 1;
630→                current_proc->pt0[vpn].kprot = PROT_READ | PROT_WRITE;
631→                current_proc->pt0[vpn].uprot = PROT_READ | PROT_WRITE;
632→                current_proc->pt0[vpn].pfn = pfn;
633→            }
634→            current_proc->user_stack_base = (void *)new_stack_base;
635→            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
636→            return;
637→        }
638→    }
639→
640→kill_proc:
641→    TracePrintf(0, "TRAP_MEMORY: Process %d terminated (addr %p, code %d)\n",
642→                current_proc->pid, info->addr, info->code);
643→    fprintf(stderr, "Process %d terminated: memory exception at %p\n",
644→            current_proc->pid, info->addr);
645→    kern_exit(ERROR, info);
646→}
