657→static void
658→trap_tty_receive(ExceptionInfo *info)
659→{
660→    int tty_id = info->code;
661→    tty_buf_t *buf;
662→
663→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;
664→
665→    /* Allocate a buffer and read the line */
666→    buf = (tty_buf_t *)malloc(sizeof(tty_buf_t));
667→    if (!buf) return;
668→
669→    buf->len = TtyReceive(tty_id, buf->data, TERMINAL_MAX_LINE);
670→    buf->offset = 0;
671→    buf->next = NULL;
672→
673→    /* Add to the input buffer queue for this terminal */
674→    if (!tty_read_bufs[tty_id]) {
675→        tty_read_bufs[tty_id] = buf;
676→    } else {
677→        tty_buf_t *last = tty_read_bufs[tty_id];
678→        while (last->next) last = last->next;
679→        last->next = buf;
680→    }
681→
682→    /* Wake up blocked reader if any */
683→    if (tty_read_blocked[tty_id]) {
684→        pcb_t *p = tty_read_blocked[tty_id];
685→        tty_read_blocked[tty_id] = p->next;
686→        p->next = NULL;
687→        enqueue_ready(p);
688→    }
689→}
