691→static void
692→trap_tty_transmit(ExceptionInfo *info)
693→{
694→    int tty_id = info->code;
695→    fprintf(stderr, "DBG: TRAP_TTY_TRANSMIT tty=%d\n", tty_id);
696→    TracePrintf(0, "TRAP_TTY_TRANSMIT: tty=%d\n", tty_id);
697→
698→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return;
699→
700→    /* Unblock the process that was writing */
701→    pcb_t *done = tty_write_active[tty_id];
702→    tty_write_active[tty_id] = NULL;
703→
704→    if (done) {
705→        enqueue_ready(done);
706→    }
707→
708→    /* Start next pending write if any */
709→    if (tty_write_pending[tty_id]) {
710→        tty_write_info_t *wi = tty_write_pending[tty_id];
711→        tty_write_pending[tty_id] = wi->next;
712→
713→        tty_write_active[tty_id] = wi->proc;
714→        memcpy(tty_xmit_buf[tty_id], wi->buf, wi->len);
715→        TtyTransmit(tty_id, tty_xmit_buf[tty_id], wi->len);
716→        free(wi);
717→    }
718→}
