1160→static int
1161→kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info)
1162→{
1163→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
1164→    if (len < 0 || len > TERMINAL_MAX_LINE) return ERROR;
1165→    if (len == 0) return 0;
1166→    if (validate_user_buf(current_proc, buf, len, 0) < 0) return ERROR;
1167→
1168→    TracePrintf(0, "kern_ttywrite: tty_id=%d len=%d\n", tty_id, len);
1169→    if (!tty_write_active[tty_id]) {
1170→        /* Terminal is free, start transmitting */
1171→        memcpy(tty_xmit_buf[tty_id], buf, len);
1172→        tty_write_active[tty_id] = current_proc;
1173→        current_proc->state = PROC_BLOCKED_TTY_WRITE;
1174→        TracePrintf(0, "kern_ttywrite: calling TtyTransmit\n");
1175→        TtyTransmit(tty_id, tty_xmit_buf[tty_id], len);
1176→        TracePrintf(0, "kern_ttywrite: TtyTransmit returned, scheduling\n");
1177→        schedule(info);
1178→    } else {
1179→        /* Terminal busy, queue this write with its own buffer */
1180→        tty_write_info_t *wi = (tty_write_info_t *)malloc(sizeof(tty_write_info_t));
1181→        if (!wi) return ERROR;
1182→        memcpy(wi->buf, buf, len);
1183→        wi->len = len;
1184→        wi->tty_id = tty_id;
1185→        wi->proc = current_proc;
1186→        wi->next = NULL;
1187→
1188→        /* Add to pending queue */
1189→        if (!tty_write_pending[tty_id]) {
1190→            tty_write_pending[tty_id] = wi;
1191→        } else {
1192→            tty_write_info_t *last = tty_write_pending[tty_id];
1193→            while (last->next) last = last->next;
1194→            last->next = wi;
1195→        }
1196→
1197→        current_proc->state = PROC_BLOCKED_TTY_WRITE;
1198→        schedule(info);
1199→    }
1200→
1201→    return len;
1202→}
